import React, { useState } from 'react';
import { sprintf, __ } from '@wordpress/i18n';
import {toast} from "react-toastify";

export default function ProductsSelected( props ) {
    const [isOpen, setIsOpen] = useState( props.isOpen ? true : false );
    const [isFocused, setIsFocused] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [affiliateUrlFocused, setAffiliateUrlFocused] = useState({});
    const marketplace = props.marketplace ? props.marketplace : 'amazon';
    const isMercado = marketplace === 'mercado';

    const prepareErrorString = (errors) => {
        let error_string = __('There was an error validating product ids: ', 'hostinger-affiliate-plugin');

        for (let key in errors) {
            if (errors.hasOwnProperty(key)) {
                error_string += errors[key] + ' ';
            }
        }

        return error_string;
    }

    const handleAffiliateUrlChange = (asin, value) => {
        const cleanAsin = asin.replace(/ /g,'');
        const updatedItems = { ...props.attributes.items };

        if (updatedItems[cleanAsin]) {
            updatedItems[cleanAsin] = {
                ...updatedItems[cleanAsin],
                affiliate_url: value
            };

            props.setAttributes({
                items: updatedItems
            });
        }
    };

    const validateAffiliateUrls = () => {
        if (!isMercado) {
            return true;
        }

        let asins = props.attributes.asin ? props.attributes.asin.split(',') : [];
        let isValid = true;
        let missingUrls = [];

        for (let asin of asins) {
            const cleanAsin = asin.replace(/ /g,'');
            if (!props.attributes.items?.[cleanAsin]?.affiliate_url) {
                isValid = false;
                missingUrls.push(asin);
            }
        }

        if (!isValid) {
            toast.error(__('Please provide affiliate URLs for all products', 'hostinger-affiliate-plugin'));
            return false;
        }

        return true;
    };

    const handleInputKeyDown = (e) => {
        if (e.key === 'Enter') {
            if(props.validateAsins(props.attributes.asin_manual)) {
                setIsLoading(true);

                fetch(hst_affiliate_data.rest_base_url + 'hostinger-affiliate-plugin/v1/validate-items', {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'X-WP-Nonce': hst_affiliate_data.nonce,
                        'X-Hpanel-Domain': hst_affiliate_data.block['domain_settings']['domain'],
                        'Cache-Control': 'no-cache'
                    },
                    body: JSON.stringify({
                        items: props.attributes.asin_manual,
                        layout: props.attributes.display_type,
                        marketplace: marketplace
                    })
                })
                    .then((response) => {
                        return response.json();
                    })
                    .then((data) => {
                        setIsLoading(false)
                        if(data.data.errors) {
                            toast.error(prepareErrorString(data.data.errors));
                        } else if(data.data.status >= 500) {
                            toast.error( __('There was fatal server error while processing your request.', 'hostinger-affiliate-plugin') );
                        } else {
                            props.appendItemData(data.items);
                            props.setAttributes({
                                asin: props.attributes.asin_manual,
                                asin_manual: props.attributes.asin_manual,
                                product_selector : 'layout'
                            });
                        }
                    });

            } else {
                toast.error( __('ASIN validation failed. Please check entered product ASIN!', 'hostinger-affiliate-plugin') );
            }
        }
    }

    const handleAccordionToggle = () => {
        setIsOpen(!isOpen);
        props.setAttributes({ products_selected_open: !isOpen });
    };

    const handleDeleteItem = (index) => {
        props.removeItem(index)
    };

    const getImageUrl = (asin) => {
        asin = asin.replace(/ /g,'');

        if (props.attributes.items && props.attributes.items.hasOwnProperty(asin)) {
            return props.attributes.items[asin].image_url;
        } else {
            return hst_affiliate_data.plugin_url + '/assets/img/product-no-image.svg';
        }
    }

    const getName = (asin) => {
        asin = asin.replace(/ /g,'');

        if (props.attributes.items && props.attributes.items.hasOwnProperty(asin)) {
            return props.attributes.items[asin].title;
        } else {
            return 'N/A';
        }
    }

    const getAffiliateUrl = (asin) => {
        asin = asin.replace(/ /g,'');

        if (props.attributes.items && props.attributes.items.hasOwnProperty(asin)) {
            return props.attributes.items[asin].affiliate_url || '';
        } else {
            return '';
        }
    }

    const getProductUrl = (asin) => {
        asin = asin.replace(/ /g,'');

        if (props.attributes.items && props.attributes.items.hasOwnProperty(asin)) {
            return props.attributes.items[asin].url || '';
        } else {
            return '';
        }
    }

    const copyToClipboard = (text) => {
        navigator.clipboard.writeText(text).then(
            () => {
                toast.success(__('Copied to clipboard!', 'hostinger-affiliate-plugin'));
            },
            () => {
                toast.error(__('Failed to copy!', 'hostinger-affiliate-plugin'));
            }
        );
    };

    const productsSelected = [];

    const productList = [];

    let asins = props.attributes.asin ? props.attributes.asin.split(',') : [];

    if(asins.length == 0) {
        productsSelected.push(<>
            { __( 'No products selected', 'hostinger-affiliate-plugin' ) }
            </>);
    } else {
        productsSelected.push(<>
            {asins.length} { __( (asins.length > 1 ? 'products' : 'product'), 'hostinger-affiliate-plugin') } { __( 'selected', 'hostinger-affiliate-plugin') }
        </>);
    }

    if(asins.length) {
        productList.push(<>
            <ul className="hostinger-block-products-selected__items-list">
                {asins.map((asin, index) => (
                    <li className="hostinger-block-products-selected__items-list-item"
                        key={index}>
                        <div className={`hostinger-block-products-selected__list-item-wrap`}>
                            <div className={`hostinger-block-products-selected__list-item-thumb ${((props.attributes.items && props.attributes.items.hasOwnProperty(asin.replace(/ /g,''))) ? '' : 'hostinger-block-products-selected__list-item-thumb--no-image')}`}>
                                <img src={ getImageUrl(asin) } title={ getName(asin) } />
                            </div>
                            <div className="hostinger-block-products-selected__list-item-info">
                                <div className="hostinger-block-products-selected__list-item-name">
                                    {isMercado ? (
                                        <a
                                            href={getProductUrl(asin)}
                                            target="_blank"
                                            rel="sponsored noopener noreferrer"
                                            className="hostinger-block-products-selected__list-item-link"
                                        >
                                            { (getName(asin).length > 70) ? getName(asin).slice(0, 70) + '...' : getName(asin) }

                                            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 16 16" fill="none">
                                                <path d="M2.5 5.24805C2.5 3.72926 3.73122 2.49805 5.25 2.49805H6C6.41421 2.49805 6.75 2.83383 6.75 3.24805C6.75 3.66226 6.41421 3.99805 6 3.99805H5.25C4.55964 3.99805 4 4.55769 4 5.24805V10.6861C4 11.3765 4.55964 11.9361 5.25 11.9361H10.7508C11.4411 11.9361 12.0008 11.3765 12.0008 10.6861V10.0002C12.0008 9.58603 12.3366 9.25024 12.7508 9.25024C13.165 9.25024 13.5008 9.58603 13.5008 10.0002V10.6861C13.5008 12.2049 12.2696 13.4361 10.7508 13.4361H5.25C3.73122 13.4361 2.5 12.2049 2.5 10.6861V5.24805Z" fill="#1D1E20"/>
                                                <path d="M12 5.06101L8.03033 9.03068C7.73744 9.32357 7.26256 9.32357 6.96967 9.03068C6.67678 8.73779 6.67678 8.26291 6.96967 7.97002L10.9393 4.00035H9C8.58579 4.00035 8.25 3.66456 8.25 3.25035C8.25 2.83614 8.58579 2.50035 9 2.50035L12.25 2.50035C12.9404 2.50035 13.5 3.05999 13.5 3.75035V7.00035C13.5 7.41456 13.1642 7.75035 12.75 7.75035C12.3358 7.75035 12 7.41456 12 7.00035V5.06101Z" fill="#1D1E20"/>
                                            </svg>
                                        </a>
                                    ) : (
                                        <>{ (getName(asin).length > 70) ? getName(asin).slice(0, 70) + '...' : getName(asin) }</>
                                    )}
                                </div>
                                <div className="hostinger-block-products-selected__list-item-asin">
                                    { isMercado ? __('Product ID', 'hostinger-affiliate-plugin') : __('ASIN', 'hostinger-affiliate-plugin') }: <span>{ asin }</span>
                                </div>
                            </div>
                            <div className="hostinger-block-products-selected__list-item-delete">
                                <div
                                    onClick={(e) => {
                                        e.preventDefault();
                                        handleDeleteItem(index);
                                    }}
                                >
                                    <svg
                                        xmlns="http://www.w3.org/2000/svg"
                                        width="24"
                                        height="24"
                                        viewBox="0 0 24 24"
                                        fill="none"
                                    >
                                        <path d="M7 21C6.45 21 5.97917 20.8042 5.5875 20.4125C5.19583 20.0208 5 19.55 5 19V6C4.71667 6 4.47917 5.90417 4.2875 5.7125C4.09583 5.52083 4 5.28333 4 5C4 4.71667 4.09583 4.47917 4.2875 4.2875C4.47917 4.09583 4.71667 4 5 4H9C9 3.71667 9.09583 3.47917 9.2875 3.2875C9.47917 3.09583 9.71667 3 10 3H14C14.2833 3 14.5208 3.09583 14.7125 3.2875C14.9042 3.47917 15 3.71667 15 4H19C19.2833 4 19.5208 4.09583 19.7125 4.2875C19.9042 4.47917 20 4.71667 20 5C20 5.28333 19.9042 5.52083 19.7125 5.7125C19.5208 5.90417 19.2833 6 19 6V19C19 19.55 18.8042 20.0208 18.4125 20.4125C18.0208 20.8042 17.55 21 17 21H7ZM17 6H7V19H17V6ZM9 17H11V8H9V17ZM13 17H15V8H13V17Z" fill="#FC5185"/>
                                    </svg>
                                </div>
                            </div>
                        </div>
                        {isMercado && (
                            <div className={`hostinger-block-products-selected__list-item-mercado`}>
                                <div className="hostinger-block-products-selected__list-item-product-url">
                                    <div className="field-container field-container--disabled">
                                        <div className="field-holder">
                                            <div className={`field`}>
                                                <fieldset className={`field-border field-border--filled`}>
                                                    <legend className={`field-border__legend field-border__legend--filled field-border__legend-text`}>
                                                        <span>{__('Product URL', 'hostinger-affiliate-plugin')}</span>
                                                    </legend>
                                                </fieldset>
                                                <div className={`field-label field-label--filled`}>
                                                    <span>{__('Product URL', 'hostinger-affiliate-plugin')}</span>
                                                </div>
                                                <div className="field__container">
                                                    <div className="field__input field__input--with-action">
                                                        <div className="field__text" tabIndex="-1">
                                                            <input
                                                                type="text"
                                                                value={getProductUrl(asin)}
                                                                disabled
                                                            />
                                                        </div>
                                                        <div className="field__action">
                                                            <button
                                                                className="field__action-button"
                                                                onClick={() => copyToClipboard(getProductUrl(asin))}
                                                                title={__('Copy to clipboard', 'hostinger-affiliate-plugin')}
                                                            >
                                                                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none">
                                                                    <path d="M5 22C4.45 22 3.97917 21.8042 3.5875 21.4125C3.19583 21.0208 3 20.55 3 20V6H5V20H16V22H5ZM9 18C8.45 18 7.97917 17.8042 7.5875 17.4125C7.19583 17.0208 7 16.55 7 16V4C7 3.45 7.19583 2.97917 7.5875 2.5875C7.97917 2.19583 8.45 2 9 2H18C18.55 2 19.0208 2.19583 19.4125 2.5875C19.8042 2.97917 20 3.45 20 4V16C20 16.55 19.8042 17.0208 19.4125 17.4125C19.0208 17.8042 18.55 18 18 18H9ZM9 16H18V4H9V16Z" fill="#6D7081"/>
                                                                </svg>
                                                            </button>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                                <div className="hostinger-block-products-selected__list-item-affiliate-url">
                                    <div className="field-container">
                                        <div className="field-holder">
                                            <div className={`field ${affiliateUrlFocused[asin] ? "field--focused" : ""}`}>
                                                <fieldset className={`field-border field-border--filled ${affiliateUrlFocused[asin] ? "field-border--focused" : ""}`}>
                                                    <legend className={`field-border__legend field-border__legend--filled ${affiliateUrlFocused[asin] ? "field-border__legend--active" : ""} field-border__legend-text`}>
                                                        <span>{__('Affiliate URL', 'hostinger-affiliate-plugin')}</span>
                                                    </legend>
                                                </fieldset>
                                                <div className={`field-label field-label--filled ${affiliateUrlFocused[asin] ? "field-label--active" : ""}`}>
                                                    <span>{__('Affiliate URL', 'hostinger-affiliate-plugin')}</span>
                                                </div>
                                                <div className="field__container">
                                                    <div className="field__input">
                                                        <div className="field__text" tabIndex="-1">
                                                            <input
                                                                type="text"
                                                                value={getAffiliateUrl(asin)}
                                                                onBlur={() => {
                                                                    setAffiliateUrlFocused({...affiliateUrlFocused, [asin]: false});
                                                                }}
                                                                onFocus={() => {
                                                                    setAffiliateUrlFocused({...affiliateUrlFocused, [asin]: true});
                                                                }}
                                                                onChange={(event) => {
                                                                    handleAffiliateUrlChange(asin, event.target.value);
                                                                }}
                                                                placeholder={__('Affiliate URL', 'hostinger-affiliate-plugin')}
                                                            />
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        )}
                    </li>
                ))}
            </ul>
        </>)
    }

    // Expose validateAffiliateUrls function to parent component
    if (props.onValidate && typeof props.onValidate === 'function') {
        props.onValidate(validateAffiliateUrls);
    }

    return (
        <div className={`hostinger-block-products-selected ${(isLoading ? 'hostinger-block-products-selected--is-loading' : '')}`}>
            <div
                className={`hostinger-block-products-selected__accordion ${(!isOpen ? 'hostinger-block-products-selected__accordion--is-hidden' : 'hostinger-block-products-selected__accordion--is-open')}`}
                onClick={handleAccordionToggle}>

                <div className="hostinger-block-products-selected__accordion-title">
                    { productsSelected }
                </div>

                <div className="hostinger-block-products-selected__accordion-arrow">
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none">
                        <path
                            d="M11.9998 14.95C11.8665 14.95 11.7415 14.9292 11.6248 14.8875C11.5081 14.8458 11.3998 14.775 11.2998 14.675L6.6998 10.075C6.51647 9.89166 6.4248 9.65833 6.4248 9.37499C6.4248 9.09166 6.51647 8.85833 6.6998 8.67499C6.88314 8.49166 7.11647 8.39999 7.3998 8.39999C7.68314 8.39999 7.91647 8.49166 8.0998 8.67499L11.9998 12.575L15.8998 8.67499C16.0831 8.49166 16.3165 8.39999 16.5998 8.39999C16.8831 8.39999 17.1165 8.49166 17.2998 8.67499C17.4831 8.85833 17.5748 9.09166 17.5748 9.37499C17.5748 9.65833 17.4831 9.89166 17.2998 10.075L12.6998 14.675C12.5998 14.775 12.4915 14.8458 12.3748 14.8875C12.2581 14.9292 12.1331 14.95 11.9998 14.95Z"
                            fill="#673DE6"
                        />
                    </svg>
                </div>
            </div>

            {isOpen && (
                <div>
                    <div className="hostinger-block-products-selected__input-wrap">
                        <div className="field-container">
                            <div className="field-holder">
                                <div className={ `field ${isFocused ? "field--focused" : ""}` }>
                                    <fieldset className={ `field-border field-border--filled ${isFocused ? "field-border--focused" : ""}` }>
                                        <legend className={ `field-border__legend field-border__legend--filled ${isFocused ? "field-border__legend--active" : ""} field-border__legend-text` }>
                                            <span>
                                                { isMercado
                                                    ? __('Enter product ID here', 'hostinger-affiliate-plugin')
                                                    : __('Enter ASIN here', 'hostinger-affiliate-plugin') }
                                            </span>
                                        </legend>
                                    </fieldset>
                                    <div className={ `field-label field-label--filled ${isFocused ? "field-label--active" : ""}` }>
                                        <span>
                                            { isMercado
                                            ? __('Enter product ID here', 'hostinger-affiliate-plugin')
                                            : __('Enter ASIN here', 'hostinger-affiliate-plugin') }
                                        </span>
                                    </div>
                                    <div className="field__container">
                                        <div className="field__input">
                                            <div className="field__text" tabIndex="-1">
                                                <input
                                                    type="text"
                                                    value={ props.attributes.asin_manual }
                                                    onBlur = { () => setIsFocused(false) }
                                                    onFocus = { () => setIsFocused(true) }
                                                    onChange= { (event) => props.setAttributes( { asin_manual: event.target.value } ) }
                                                    onKeyDown = { handleInputKeyDown }
                                                />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                                <div className="field-info__hint-holder">
                                    { isMercado
                                        ? __( 'Multiple product id values can be separated by comma. Press Enter to save changes.', 'hostinger-affiliate-plugin' )
                                        : __( 'Multiple ASIN values can be separated by comma. Press Enter to save changes.', 'hostinger-affiliate-plugin' ) }
                                </div>
                            </div>
                        </div>
                    </div>
                    <div className="hostinger-block-products-selected__items-list-wrap">
                        { productList }
                        <div className="hostinger-block-products-selected__button-wrap">
                            <button
                                type="button"
                                data-marketplace={marketplace}
                                className={ `hostinger-block-button hostinger-block-button--is-big hostinger-block-button--is-primary-outline hostinger-affiliate__open-search-modal hostinger-affiliate__open-search-modal--is-appendable ${props.attributes.display_type == "single_product_card" ? "hostinger-affiliate__open-search-modal--is-single" : "hostinger-affiliate__open-search-modal--is-multiple"}` }
                            >
                                <div className="hostinger-block-button__icon">
                                    <svg xmlns="http://www.w3.org/2000/svg" width="25" height="24" viewBox="0 0 25 24" fill="none">
                                        <path d="M11.5 13H6.5C6.21667 13 5.97917 12.9042 5.7875 12.7125C5.59583 12.5208 5.5 12.2833 5.5 12C5.5 11.7167 5.59583 11.4792 5.7875 11.2875C5.97917 11.0958 6.21667 11 6.5 11H11.5V6C11.5 5.71667 11.5958 5.47917 11.7875 5.2875C11.9792 5.09583 12.2167 5 12.5 5C12.7833 5 13.0208 5.09583 13.2125 5.2875C13.4042 5.47917 13.5 5.71667 13.5 6V11H18.5C18.7833 11 19.0208 11.0958 19.2125 11.2875C19.4042 11.4792 19.5 11.7167 19.5 12C19.5 12.2833 19.4042 12.5208 19.2125 12.7125C19.0208 12.9042 18.7833 13 18.5 13H13.5V18C13.5 18.2833 13.4042 18.5208 13.2125 18.7125C13.0208 18.9042 12.7833 19 12.5 19C12.2167 19 11.9792 18.9042 11.7875 18.7125C11.5958 18.5208 11.5 18.2833 11.5 18V13Z" fill="#673DE6"/>
                                    </svg>
                                </div>
                                { __( 'Add a new product', 'hostinger-affiliate-plugin' ) }
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
