import React, { useState, useEffect } from "react";
import { __ } from "@wordpress/i18n";
import { TextControl } from '@wordpress/components';

import type { searchForProductsProps } from '../types';
import {toast, ToastContainer} from "react-toastify";
import ProductsSelected from "../../../amazon-gutenberg-block/src/components/products_selected";

const SearchForProducts = (props: searchForProductsProps) => {
    const [loading, setLoading] = useState(false);
    const [searchInput, setSearchInput] = useState('');
    const [isHovered, setIsHovered] = useState(false);

    useEffect(() => {
        if (props.editProps.attributes.product_selector === 'layout' && !props.editProps.attributes.list_layout) {
            const firstLayoutKey = Object.keys(props.list_layouts)[0];
            if (firstLayoutKey) {
                props.editProps.setAttributes({ list_layout: props.list_layouts[firstLayoutKey].value });
            }
        }
    }, [props.editProps.attributes.product_selector]);

    let content = [];

    const addProduct = (e) => {
        if (searchInput.indexOf(hst_affiliate_data.block.mercado_product_prefix) === -1) {
            const keywordSearchInput = document.querySelector('input[name="hostinger-affiliate-product-keyword-search"]');
            if (keywordSearchInput) {
                document.dispatchEvent(
                    new CustomEvent('triggerSearchModal', {
                        bubbles: true,
                        detail: {
                            multiple: props.hasMultiple,
                            marketplace: 'mercado',
                        }
                    })
                );

                keywordSearchInput.value = searchInput;

                document.dispatchEvent(new CustomEvent('doSearch', { bubbles: true }));
            }

            return;
        }

        setLoading(true);

        fetch(hst_affiliate_data.rest_base_url + 'hostinger-affiliate-plugin/v1/validate-items', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-WP-Nonce': hst_affiliate_data.nonce,
                'X-Hpanel-Domain': hst_affiliate_data.block['domain_settings']['domain'],
                'Cache-Control': 'no-cache'
            },
            body: JSON.stringify({
                items: searchInput,
                layout: props.editProps.attributes.display_type,
                marketplace: 'mercado'
            })
        })
            .then((response) => {
                return response.json();
            })
            .then((data) => {
                setLoading(false)
                if(data.data.errors) {
                    toast.error(props.prepareErrorString(data.data.errors));
                } else if(data.data.status >= 500) {
                    toast.error( __('There was fatal server error while processing your request.', 'hostinger-affiliate-plugin') );
                } else {
                    props.appendItemData(data.items);

                    let attributes = {
                        asin: searchInput,
                        ready: true
                    };

                    if (props.hasMultiple) {
                        attributes.product_selector = 'multiple';
                        attributes.products_selected_open = true;
                    } else {
                        attributes.ready = true;
                    }

                    props.editProps.setAttributes(attributes);
                }
            });
    }

    const addProductsButton = (): boolean => {
        return !props.editProps.attributes.asin || loading;
    }

    if( props.editProps.attributes.product_selector == '' ) {
        content.push(
            <>
                <div className="hostinger-block-search-for-products__button-wrap">
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" className="hostinger-block-search-for-products__icon-search">
                        <path fill-rule="evenodd" clip-rule="evenodd" d="M15.3234 16.7366C13.9316 17.8253 12.1792 18.4742 10.2752 18.4742C5.74646 18.4742 2.0752 14.803 2.0752 10.2742C2.0752 5.74548 5.74646 2.07422 10.2752 2.07422C14.8039 2.07422 18.4752 5.74548 18.4752 10.2742C18.4752 12.1782 17.8263 13.9306 16.7376 15.3224L21.632 20.2169C22.0225 20.6075 22.0225 21.2406 21.632 21.6311C21.2415 22.0217 20.6083 22.0217 20.2178 21.6311L15.3234 16.7366ZM16.4752 10.2742C16.4752 13.6984 13.6994 16.4742 10.2752 16.4742C6.85103 16.4742 4.0752 13.6984 4.0752 10.2742C4.0752 6.85005 6.85103 4.07422 10.2752 4.07422C13.6994 4.07422 16.4752 6.85005 16.4752 10.2742Z" fill="#727586"/>
                    </svg>
                    <div style={{ display: 'flex', alignItems: 'stretch', width: '100%' }}>
                        <div style={{ flex: 1, marginRight: '10px' }}>
                            <TextControl
                                key = "hostinger-block-search-for-products__product-id-field"
                                className = "hostinger-block-search-for-products__product-id-field"
                                placeholder = { __( 'Search for products or enter a product ID', 'hostinger-affiliate-plugin') }
                                value = { searchInput }
                                onChange = { (value) => setSearchInput(value) }
                                onKeyDown = {(event) => {
                                    if (event.key === 'Enter') {
                                        event.preventDefault();
                                        addProduct(event);
                                    }
                                }}
                                disabled = { loading }
                                style={{ height: '100%' }}
                            />
                        </div>
                        <button
                            className="hostinger-search-button"
                            onClick = {(event) => {
                                event.preventDefault();
                                addProduct(event);
                            }}
                            disabled={loading || !searchInput}
                            onMouseEnter={() => setIsHovered(true)}
                            onMouseLeave={() => setIsHovered(false)}
                            style={{
                                color: 'var(--primary--500)',
                                backgroundColor: isHovered ? 'var(--primary--50)' : 'var(--neutral--0)',
                                textAlign: 'center',
                                fontFamily: "'DM Sans', sans-serif",
                                fontSize: '14px',
                                fontStyle: 'normal',
                                fontWeight: '700',
                                lineHeight: '24px',
                                border: 'none',
                                borderRadius: '8px',
                                padding: '8px 16px',
                                cursor: loading || !searchInput ? 'not-allowed' : 'pointer',
                                opacity: loading || !searchInput ? '0.7' : '1',
                                transition: 'all 0.2s ease-in-out',
                                minWidth: '100px',
                                height: '48px',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center'
                            }}
                        >
                            {__('Search', 'hostinger-affiliate-plugin')}
                        </button>
                    </div>
                </div>
            </>
        );
    }

    if( props.editProps.attributes.product_selector == 'layout' ) {

        content.push(
            <>
                <ProductsSelected
                    attributes={props.editProps.attributes}
                    appendItemData={props.appendItemData}
                    setAttributes={props.editProps.setAttributes}
                    removeItem={props.removeItem}
                    validateAsins={props.validateAsins}
                    isOpen={props.editProps.attributes.products_selected_open}
                    marketplace={'mercado'}
                >
                </ProductsSelected>
            </>
        )

        content.push(
            <>
                <div
                    className="hostinger-block-product-selector__layout-select-title"
                >
                    { __( 'Choose the layout of your product list', 'hostinger-affiliate-plugin' ) }
                </div>
                <div
                    className="hostinger-block-product-selector__layout-grid"
                >
                    { Object.entries(props.list_layouts).map((type, index) => {
                        return (
                            <div
                                key="index"
                                className={`hostinger-block-product-selector__layout-item ${(props.editProps.attributes.list_layout == type[1].value ? 'hostinger-block-product-selector__layout-item--is-selected' : '')}`}
                                onClick={ () => props.editProps.setAttributes({ list_layout: type[1].value })}
                            >
                                <div className="hostinger-block-product-selector__layout-item-img">
                                    <img src={hst_affiliate_data.plugin_url + 'assets/img/' + type[1].image} alt="" />
                                </div>
                                <div className="hostinger-block-product-selector__layout-item-title">
                                    { type[1].label }
                                </div>
                            </div>
                        )
                    })}
                </div>
                <div className="hostinger-block-product-selector__snackbar">
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none">
                        <path d="M12 2C6.477 2 2 6.477 2 12C2 17.523 6.477 22 12 22C17.523 22 22 17.523 22 12C22 6.477 17.523 2 12 2ZM13 17H11V11H13V17ZM13 9H11V7H13V9Z" fill="#727586"/>
                    </svg>
                    { __('You can also edit your product list later from the right-hand menu.', 'hostinger-affiliate-plugin') }
                </div>
                <div className="hostinger-block-product-selector__add-product-wrap">
                    <button
                        type="button"
                        disabled={ addProductsButton() }
                        className="hostinger-block-button hostinger-block-button--is-normal hostinger-block-button--is-primary"
                        onClick={ () => {
                            if (!props.editProps.attributes.list_layout) {
                                toast.error(__('Please select a layout for your product list.', 'hostinger-affiliate-plugin'));
                                return;
                            }
                            props.editProps.setAttributes({ list_layout_selected: true, ready: true });
                        }}>
                        { __('Add products', 'hostinger-affiliate-plugin') }
                    </button>
                </div>
            </>
        )

    }

    return (
        <div className="hostinger-block-search-for-products">
            { content }
            <ToastContainer />
        </div>
    );
}

export default SearchForProducts;
