import { __ } from "@wordpress/i18n";
import Button from "../components/ui/Button";
import Dropdown from "../components/ui/Dropdown";
import { useState } from "react";
import "../styles/views/table-configuration.scss";
export default function TableConfiguration({ setAttributes, attributes }) {
  const options = [
    ...hst_affiliate_data.block.tables[attributes.marketplace].map((item) => ({
      value: item.ID,
      label: item.post_title,
    })),
  ];

  const [selectedOption, setSelectedOption] = useState(options[0]);

  const handleOnSelect = (item) => {
    setSelectedOption(item);
    setAttributes({ table_id: item.value });
  };

    const onAddNewTable = () => {
        let route = attributes.marketplace === "amazon" ? "create-amazon-collection" : "create-mercado-livre-collection";
        jQuery(
            '<a href="' + hst_affiliate_data.site_url + '/wp-admin/admin.php?page=hostinger-amazon-affiliate#/' + route + '" target="blank"></a>'
        )[0].click();
    };

  const onEditTable = () => {
    setAttributes({ ready: true });
  };

  return (
    <div className="table-configuration">
      <div className="table-configuration__container">
        <h2 className="text-heading-2 h-mb-4">
          {__(
            "Use the saved table configuration",
            "hostinger-affiliate-plugin"
          )}
        </h2>

        <p className="text-body-1 h-mb-24">
          {__(
            "You can edit the existing table configuration after this step",
            "hostinger-affiliate-plugin"
          )}
        </p>

        <div className="d-flex h-mb-24">
          <Dropdown
            className="h-mr-16"
            options={options}
            onSelect={handleOnSelect}
            placeholder={__(
              "Choose the table configuration",
              "hostinger-affiliate-plugin"
            )}
          />

          <Button
            onClick={onEditTable}
            disabled={!parseInt(attributes.table_id)}
          >
            {__("Continue", "hostinger-affiliate-plugin")}
          </Button>
        </div>

        <p className="d-flex justify-content-center h-mb-24">
          {__("or", "hostinger-affiliate-plugin")}
        </p>

        <Button className="w-100" onClick={onAddNewTable} variant="outline">
          <svg
            part="svg"
            xmlns="http://www.w3.org/2000/svg"
            aria-hidden="true"
            aria-labelledby="icon-add"
            focusable="false"
            viewBox="0 0 24 24"
            style={{ width: "24px", height: "24px" }} // Correct style usage
          >
            <g>
              <path
                fillRule="evenodd"
                fill="#673de6"
                clipRule="evenodd"
                d="M19 13H13V19H11V13H5V11H11V5H13V11H19V13Z"
              ></path>
            </g>
          </svg>
          {__("Add a new table configuration", "hostinger-affiliate-plugin")}
        </Button>
      </div>
    </div>
  );
}
