import {useEffect} from "react";

import {sprintf, __} from "@wordpress/i18n";

import {useBlockProps, InspectorControls} from "@wordpress/block-editor";

import {
    SelectControl,
    PanelBody,
    ToggleControl,
    RangeControl,
    TextControl,
    TextareaControl,
    Button,
} from "@wordpress/components";

import ServerSideRender from "@wordpress/server-side-render";

import HostingerLogo from "../../amazon-gutenberg-block/src/components/logo";
import SelectedDisplayType from "../../amazon-gutenberg-block/src/components/selected_display_type";
import ProductSelector from "../../amazon-gutenberg-block/src/components/product_selector";
import ProductSelectorMultiple from "../../amazon-gutenberg-block/src/components/product_selector_multiple";
import ProductListTypeSelector from "../../amazon-gutenberg-block/src/components/product_list_type_selector";
import ProductListBestsellers from "../../amazon-gutenberg-block/src/components/product_list_bestsellers";
import DisplayTypeSelector from "../../amazon-gutenberg-block/src/components/DisplayTypeSelector";
import TableConfiguration from "../../amazon-gutenberg-block/src/views/TableConfiguration";
import SearchForProducts from "./components/SearchForProducts";

export default function Edit(props) {
    const changeDisplayType = (type) => {
        let attributes = {
            display_type: type,
            ready: false,
            list_navigation: "generate_type",
            product_selector: "",
        };

        if(type === "multiple_product_list") {
            attributes.product_list_type = "manual";
        }

        props.setAttributes(attributes);
    };

    const validateAsins = (asins) => {
        let items = asins.replace(/ /g, "").toUpperCase().split(","),
            valid = true;

        items.forEach((element) => {
            if(element.indexOf(hst_affiliate_data.block.mercado_product_prefix) === -1) {
                valid = false;
            }
        });

        return valid;
    };

    const appendItemData = (items) => {
        let existingItems = props.attributes.items;

        if (!existingItems) {
            existingItems = {};
        }

        console.log(existingItems);
        console.log(items);

        existingItems = Object.assign({}, existingItems, items);

        console.log(existingItems);

        props.setAttributes({items: existingItems});
    };

    const removeItem = (index) => {
        let data = {},
            selectedAsins = props.attributes.asin
                .replace(/ /g, "")
                .toUpperCase()
                .split(",");

        let asinToRemove = selectedAsins[index];
        if (asinToRemove) {
            selectedAsins.splice(index, 1);
            data.asin = selectedAsins.join(",");
            data.asin_manual = data.asin;

            if(props.attributes.items[asinToRemove]) {
                let items = props.attributes.items;
                delete items[asinToRemove];
                data.items = items;
            }
        }

        if (data) {
            props.setAttributes(data);
        }
    };

    const searchSelected = (e) => {
        let selectedBlock = wp.data.select("core/block-editor").getSelectedBlock(),
            asinToSet,
            itemsToSet;

        if (!selectedBlock || selectedBlock.clientId != props.clientId) {
            return false;
        }

        let existingAsin = selectedBlock.attributes.asin.replace(/ /g, "");

        if (e.detail.operation == "append") {
            let existingItems = selectedBlock.attributes.items,
                selectedAsins = existingAsin ? existingAsin.split(",") : [],
                appendedAsin = e.detail.asins ? e.detail.asins.split(",") : "";

            asinToSet = selectedAsins.concat(appendedAsin).join(",");

            if (!existingItems) {
                existingItems = {};
            }

            itemsToSet = Object.assign({}, existingItems, e.detail.items);
        } else {
            asinToSet = e.detail.asins ? e.detail.asins : "";
            itemsToSet = e.detail.items ? e.detail.items : "";
        }

        if (selectedBlock.attributes.display_type == "single_product_card") {
            props.setAttributes({
                asin: asinToSet,
                asin_manual: asinToSet,
                ready: true,
                items: itemsToSet,
            });
        } else {
            props.setAttributes({
                asin: asinToSet,
                asin_manual: asinToSet,
                product_selector: "layout",
                items: itemsToSet,
                products_selected_open: (e.detail.marketplace && e.detail.marketplace === 'mercado') ? true : false
            });
        }
    };

    const onAddNewTable = () => {
        jQuery('<a href="' + hst_affiliate_data.site_url + '/wp-admin/admin.php?page=hostinger-amazon-affiliate#/create-mercado-livre-collection" target="blank"></a>')[0].click();
    };

    const onEditTable = () => {
        jQuery('<a href="' + hst_affiliate_data.site_url + '/wp-admin/admin.php?page=hostinger-amazon-affiliate#/edit-mercado-livre-collection/' + props.attributes.table_id + '?id=' + props.attributes.table_id + '" target="blank"></a>')[0].click();
    }

    const onClickProductUrl = () => {
        let keys = Object.keys(props.attributes.items);

        if(keys.length === 0) {
            return;
        }

        let firstKey = keys[0];

        jQuery('<a href="' + props.attributes.items[firstKey].url + '" target="blank"></a>')[0].click();
    }

    const prepareErrorString = (errors) => {
        let error_string = __('There was an error: ', 'hostinger-affiliate-plugin');

        for (let key in errors) {
            if (errors.hasOwnProperty(key)) {
                error_string += errors[key] + ' ';
            }
        }

        return error_string;
    }

    useEffect(() => {
        document.addEventListener("searchSelected", searchSelected);

        return () => {
            document.removeEventListener("searchSelected", searchSelected);
        };
    }, []);

    /**
     * Title fields
     */

    let title_length_field = (
        <TextControl
            label={__("Title length", "hostinger-affiliate-plugin")}
            type="number"
            key="hostinger-affiliate-block-input-control"
            className="hostinger-affiliate-block-input-control hostinger-affiliate-block-input-title-length"
            value={props.attributes.title_length}
            min={1}
            onChange={(value) => {
                    if(value === '') {
                        value = 0;
                    }
                    props.setAttributes({title_length: parseInt(value)})
                }
            }
            help={__(
                "Maximum count of characters for the product title.",
                "hostinger-affiliate-plugin"
            )}
            disabled={!props.attributes.ready}
        />
    );

    /**
     * Description fields
     */

    let title_overwrite_enabled_field = (
        <ToggleControl
            label={__("Title overwrite enabled?", "hostinger-affiliate-plugin")}
            key="hostinger-affiliate-block-input-control"
            checked={props.attributes.title_overwrite_enabled}
            onChange={(value) =>
                props.setAttributes({title_overwrite_enabled: value})
            }
            help={__("Overwrite product title?", "hostinger-affiliate-plugin")}
            disabled={!props.attributes.ready}
        />
    );

    let description_enabled_field = (
        <ToggleControl
            label={__("Description enabled?", "hostinger-affiliate-plugin")}
            key="hostinger-affiliate-block-input-control"
            checked={props.attributes.description_enabled}
            onChange={(value) => props.setAttributes({description_enabled: value})}
            help={__("Show product description?", "hostinger-affiliate-plugin")}
            disabled={!props.attributes.ready}
        />
    );

    let description_overwrite_enabled_field = (
        <ToggleControl
            label={__("Description overwrite enabled?", "hostinger-affiliate-plugin")}
            key="hostinger-affiliate-block-input-control"
            checked={props.attributes.description_overwrite_enabled}
            onChange={(value) =>
                props.setAttributes({description_overwrite_enabled: value})
            }
            help={__("Overwrite product description?", "hostinger-affiliate-plugin")}
            disabled={!props.attributes.ready}
        />
    );

    let description_overwrite_field = (
        <TextareaControl
            label={__("Description", "hostinger-affiliate-plugin")}
            key="hostinger-affiliate-block-input-control"
            value={props.attributes.description_overwrite}
            onChange={(value) =>
                props.setAttributes({description_overwrite: value})
            }
            help={__("Overwrite product description", "hostinger-affiliate-plugin")}
            disabled={!props.attributes.ready}
        />
    );

    let description_items_field = (
        <RangeControl
            label={__("Description Items", "hostinger-affiliate-plugin")}
            type="number"
            key="hostinger-affiliate-block-input-control"
            value={props.attributes.description_items}
            onChange={(value) =>
                props.setAttributes({description_items: parseInt(value)})
            }
            min={1}
            max={15}
            help={__(
                "Count of list items in product description.",
                "hostinger-affiliate-plugin"
            )}
            disabled={!props.attributes.ready}
        />
    );

    let description_length_field = (
        <TextControl
            label={__("Description length", "hostinger-affiliate-plugin")}
            type="number"
            key="hostinger-affiliate-block-input-control"
            className="hostinger-affiliate-block-input-control hostinger-affiliate-block-input-description-length"
            min={1}
            value={props.attributes.description_length}
            onChange={(value) => {
                    if(value === '') {
                        value = 0;
                    }
                    props.setAttributes({description_length: parseInt(value)})
                }
            }
            help={__(
                "Maximum count of characters for each product description list item.",
                "hostinger-affiliate-plugin"
            )}
            disabled={!props.attributes.ready}
        />
    );

    let display_types = {
        single_product_card: {
            image: "template-single-mercado.png",
            value: "single_product_card",
            label: __("Single Product Card", "hostinger-affiliate-plugin"),
            description: __(
                "Add a single product with detailed description.",
                "hostinger-affiliate-plugin"
            ),
            disabled: false,
        },
        multiple_product_list: {
            image: "template-list-mercado.png",
            value: "multiple_product_list",
            label: __("Multiple Product List", "hostinger-affiliate-plugin"),
            description: __(
                "Add a few products and describe them briefly.",
                "hostinger-affiliate-plugin"
            ),
            disabled: false,
        },
        comparison_table: {
            image: "template-comparison-table-mercado.png",
            value: "comparison_table",
            label: __("Comparison Table", "hostinger-affiliate-plugin"),
            description: __(
                "Add multiple similar products and compare them.",
                "hostinger-affiliate-plugin"
            ),
            disabled: false,
        },
    };

    /**
     * Lists
     */

    let list_layouts = {
        list_with_description: {
            image: "list_layout_list_mercado.png",
            label: __("List with description", "hostinger-affiliate-plugin"),
            value: "list_with_description",
        },
        simplified_list: {
            image: "list_layout_simple_mercado.png",
            label: __("Simplified list", "hostinger-affiliate-plugin"),
            value: "simplified_list",
        },
        horizontal_cards: {
            image: "list_layout_horizontal_mercado.png",
            label: __("Horizontal cards", "hostinger-affiliate-plugin"),
            value: "horizontal_cards",
        },
    };

    let list_items_count_max = hst_affiliate_data.block.amazon_api_used ? 10 : 3;

    let list_items_count_field = (
        <RangeControl
            label={__("Items to show", "hostinger-affiliate-plugin")}
            type="number"
            key="hostinger-affiliate-block-input-control"
            value={props.attributes.list_items_count}
            onChange={(value) =>
                props.setAttributes({list_items_count: parseInt(value)})
            }
            min={1}
            max={list_items_count_max}
            help={__("Count of items to show in list.", "hostinger-affiliate-plugin")}
            disabled={!props.attributes.ready}
        />
    );

    /**
     * Buy Buttons
     */

    let buy_button_overwrite_enabled_field = (
        <ToggleControl
            label={__("Buy button overwrite enabled?", "hostinger-affiliate-plugin")}
            key="hostinger-affiliate-block-input-control"
            checked={props.attributes.buy_button_overwrite_enabled}
            onChange={(value) =>
                props.setAttributes({buy_button_overwrite_enabled: value})
            }
            disabled={!props.attributes.ready}
        />
    );

    let buy_button_overwrite_field = (
        <TextareaControl
            label={__("Buy button text", "hostinger-affiliate-plugin")}
            key="hostinger-affiliate-block-input-control"
            value={props.attributes.buy_button_overwrite}
            onChange={(value) =>
                props.setAttributes({buy_button_overwrite: value})
            }
            disabled={!props.attributes.ready}
        />
    );

    let content = [],
        inspector_controls = [],
        inspector_control_content = [],
        search_multiple_products = [],
        title_controls = [],
        title_control_content = [],
        description_controls = [],
        description_control_content = [],
        buy_button_controls = [],
        buy_button_controls_content = [],
        list_controls = [],
        list_control_content = [],
        template_controls = [],
        template_control_content = [],
        table_controls = [],
        table_control_content = [];

    search_multiple_products.push(
        <>
            <div
                key="components-base-control"
                className="components-base-control hostinger-affiliate-block-input-control hostinger-affiliate-block-input-control--is-or-selector"
            >
                <label className="components-base-control__label">
                    {__("OR", "hostinger-affiliate-plugin")}
                </label>
            </div>
            <div className="components-base-control"
                key="components-base-control">
                <Button
                    variant="secondary"
                    key="hostinger-affiliate-block-products-search"
                    className={`hostinger-affiliate__open-search-modal ${
                        props.attributes.display_type == "single_product_card"
                            ? "hostinger-affiliate__open-search-modal--is-single"
                            : "hostinger-affiliate__open-search-modal--is-multiple"
                    }`}
                    disabled={!props.attributes.ready}
                    data-marketplace="mercado"
                >
                    <span className="dashicons dashicons-search"></span>
                    {__(
                        " Search for product(s) without ID",
                        "hostinger-affiliate-plugin"
                    )}
                </Button>
            </div>
        </>
    );

    if(props.attributes.ready) {
        search_multiple_products.push(
            <>
                <div className="components-base-control hostinger-affiliate-block-products-url"
                    key="components-base-control">
                    <Button
                        variant="secondary"
                        key="hostinger-affiliate-block-products-url"
                        onClick={() => onClickProductUrl()}
                    >
                        {__(
                            "View Product on Mercado Livre",
                            "hostinger-affiliate-plugin"
                        )}
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M2.5 5.24805C2.5 3.72926 3.73122 2.49805 5.25 2.49805H6C6.41421 2.49805 6.75 2.83383 6.75 3.24805C6.75 3.66226 6.41421 3.99805 6 3.99805H5.25C4.55964 3.99805 4 4.55769 4 5.24805V10.6861C4 11.3765 4.55964 11.9361 5.25 11.9361H10.7508C11.4411 11.9361 12.0008 11.3765 12.0008 10.6861V10.0002C12.0008 9.58603 12.3366 9.25024 12.7508 9.25024C13.165 9.25024 13.5008 9.58603 13.5008 10.0002V10.6861C13.5008 12.2049 12.2696 13.4361 10.7508 13.4361H5.25C3.73122 13.4361 2.5 12.2049 2.5 10.6861V5.24805Z" fill="#3858e9"></path><path d="M12 5.06101L8.03033 9.03068C7.73744 9.32357 7.26256 9.32357 6.96967 9.03068C6.67678 8.73779 6.67678 8.26291 6.96967 7.97002L10.9393 4.00035H9C8.58579 4.00035 8.25 3.66456 8.25 3.25035C8.25 2.83614 8.58579 2.50035 9 2.50035L12.25 2.50035C12.9404 2.50035 13.5 3.05999 13.5 3.75035V7.00035C13.5 7.41456 13.1642 7.75035 12.75 7.75035C12.3358 7.75035 12 7.41456 12 7.00035V5.06101Z" fill="#3858e9"></path></svg>
                    </Button>
                </div>
            </>
        );
    }

    /**
     * Components
     */

    let selected_display_type_component = (
        <SelectedDisplayType
            displayType={props.attributes.display_type}
            types={display_types}
            changeDisplayType={changeDisplayType}
        ></SelectedDisplayType>
    );

    // Site editor not supported.
    if (
        pagenow && pagenow == 'site-editor'
    ) {
        return (
            <div {...useBlockProps()}>
                <HostingerLogo></HostingerLogo>
                <div className="hostinger-block-display-selector">
                    <div className="hostinger-block-display-selector__title">
                        {__(
                            "This block is not supported while using Site Editor",
                            "hostinger-affiliate-plugin"
                        )}
                    </div>

                    <div className="hostinger-block-display-selector__subtitle">
                        {__(
                            "The block you are attempting to use is currently not supported in the Site Editor. We apologize for any inconvenience this may cause. Our team is actively working to enhance compatibility, and we appreciate your understanding. For the best editing experience, please consider using post/page editor or await future updates.",
                            "hostinger-affiliate-plugin"
                        )}
                    </div>
                </div>
            </div>
        );
    }

    // If not connected, return connection message.
    if (
        hst_affiliate_data.block.mercado_status !=
        hst_affiliate_data.block.status_constants.connected
    ) {
        return (
            <div {...useBlockProps()}>
                <HostingerLogo></HostingerLogo>
                <div className="hostinger-block-display-selector">
                    <div className="hostinger-block-display-selector__title">
                        {__(
                            "Enable Mercado Livre store in settings",
                            "hostinger-affiliate-plugin"
                        )}
                    </div>

                    <div className="hostinger-block-display-selector__subtitle">
                        {__(
                            "To gain full access to this block, you need to enable Mercado Livre integration.",
                            "hostinger-affiliate-plugin"
                        )}
                    </div>

                    <div className="hostinger-block-display-selector__button-wrap">
                        <a
                            href={
                                hst_affiliate_data.block.site_url +
                                "/wp-admin/admin.php?page=hostinger#amazon-affiliate" // TODO: change link
                            }
                            className="hostinger-block-button hostinger-block-button--is-normal hostinger-block-button--is-primary"
                        >
                            {__("Connect Now", "hostinger-affiliate-plugin")}
                        </a>
                    </div>
                </div>
            </div>
        );
    }

    if (props.attributes.display_type == "single_product_card") {
        content.push(
            <>
                {selected_display_type_component}
                <SearchForProducts
                    editProps={props}
                    hasMultiple={false}
                    list_layouts={list_layouts}
                    appendItemData={appendItemData}
                    prepareErrorString={prepareErrorString}
                />
            </>
        );

        inspector_control_content.push(
            <>
                <TextControl
                    key="hostinger-affiliate-block-input-control"
                    className="hostinger-affiliate-block-input-control hostinger-affiliate-block-input-asin"
                    label={__("Affiliate URL", "hostinger-affiliate-plugin")}
                    value={props.attributes.affiliate_url}
                    disabled={!props.attributes.ready}
                    placeholder={__("Enter affiliate url", "hostinger-affiliate-plugin")}
                    onChange={(value) => props.setAttributes({affiliate_url: value})}
                />
                <TextControl
                    key="hostinger-affiliate-block-input-control"
                    className="hostinger-affiliate-block-input-control hostinger-affiliate-block-input-asin"
                    label={__("Product ID", "hostinger-affiliate-plugin")}
                    value={props.attributes.asin}
                    disabled={!props.attributes.ready}
                    placeholder={__("Enter product ID here...", "hostinger-affiliate-plugin")}
                    onChange={(value) => props.setAttributes({asin: value})}
                />
            </>
        );

        inspector_control_content.push(search_multiple_products);

        // Title overwrite

        title_control_content.push(title_overwrite_enabled_field);

        if (props.attributes.title_overwrite_enabled) {
            title_control_content.push(
                <TextControl
                    label={__("Title", "hostinger-affiliate-plugin")}
                    key="hostinger-affiliate-block-input-control"
                    className="hostinger-affiliate-block-input-control hostinger-affiliate-block-input-title-overwrite"
                    value={props.attributes.title_overwrite}
                    disabled={!props.attributes.ready}
                    onChange={(value) => props.setAttributes({title_overwrite: value})}
                    help={__("Custom product title.", "hostinger-affiliate-plugin")}
                />
            );
        } else {
            title_control_content.push(title_length_field);
        }

        // Description overwrite

        description_control_content.push(description_enabled_field);

        if (props.attributes.description_enabled) {
            description_control_content.push(description_overwrite_enabled_field);

            if (props.attributes.description_overwrite_enabled) {
                description_control_content.push(description_overwrite_field);
            } else {
                description_control_content.push(description_items_field);

                description_control_content.push(description_length_field);
            }
        }

        // Buy button overwrite

        buy_button_controls_content.push(buy_button_overwrite_enabled_field);

        if (props.attributes.buy_button_overwrite_enabled) {
            buy_button_controls_content.push(buy_button_overwrite_field);
        }

        // Enable description
        if (!props.attributes.description_forced) {
            props.setAttributes({
                description_enabled: true,
                description_forced: true
            });
        }
    }

    if (props.attributes.display_type == "multiple_product_list") {
        template_control_content.push(
            <>
                <SelectControl
                    label={__("Layout", "hostinger-affiliate-plugin")}
                    value={props.attributes.list_layout}
                    options={[
                        {
                            value: "",
                            label: __("-- Select from list --", "hostinger-affiliate-plugin"),
                        },
                        {
                            label: __("List with description", "hostinger-affiliate-plugin"),
                            value: "list_with_description",
                        },
                        {
                            label: __("Simplified list", "hostinger-affiliate-plugin"),
                            value: "simplified_list",
                        },
                        {
                            label: __("Horizontal cards", "hostinger-affiliate-plugin"),
                            value: "horizontal_cards",
                        },
                    ]}
                    disabled={!props.attributes.ready}
                    onChange={(value) => props.setAttributes({list_layout: value})}
                />
            </>
        );

        if (props.attributes.list_navigation == "generate_type") {
            content.push(
                <>
                    {selected_display_type_component}
                    <SearchForProducts
                        editProps={props}
                        hasMultiple={true}
                        list_layouts={list_layouts}
                        appendItemData={appendItemData}
                        removeItem={removeItem}
                        validateAsins={validateAsins}
                        prepareErrorString={prepareErrorString}
                    />
                </>
            );
        }

        if (props.attributes.list_navigation == "manual") {
            content.push(
                <>
                    {selected_display_type_component}
                    <ProductSelectorMultiple
                        attributes={props.attributes}
                        setAttributes={props.setAttributes}
                        list_layouts={list_layouts}
                        appendItemData={appendItemData}
                        removeItem={removeItem}
                        validateAsins={validateAsins}
                    ></ProductSelectorMultiple>
                </>
            );
        }

        if (props.attributes.list_layout) {
            title_control_content.push(title_length_field);

            list_control_content.push(<>
                <ToggleControl
                    label={__("Display Bestseller #", "hostinger-affiliate-plugin")}
                    key="hostinger-affiliate-block-input-control"
                    checked={props.attributes.bestseller_label_enabled}
                    onChange={(value) => props.setAttributes({bestseller_label_enabled: value})}
                    disabled={!props.attributes.ready}
                />
            </>);

            if (props.attributes.product_list_type == "bestsellers") {
                list_control_content.push(list_items_count_field);
            }
        }

        if (props.attributes.list_layout == "list_with_description") {
            description_control_content.push(description_enabled_field);

            if (props.attributes.description_enabled) {
                description_control_content.push(description_items_field);

                description_control_content.push(description_length_field);
            }

            // Enable description
            if (!props.attributes.description_forced) {
                props.setAttributes({
                    description_enabled: true,
                    description_forced: true
                });
            }
        }

        // Buy button overwrite

        buy_button_controls_content.push(buy_button_overwrite_enabled_field);

        if (props.attributes.buy_button_overwrite_enabled) {
            buy_button_controls_content.push(buy_button_overwrite_field);
        }

        if (props.attributes.product_list_type == "manual") {
            inspector_control_content.push(<>
                <>
                    <div
                        key="components-base-control"
                        className="hostinger-affiliate-block-input-control hostinger-affiliate-block-input-control--is-asin-label-holder"
                    >
                        <label className="components-truncate components-text components-input-control__label">
                            {__("Product ID", "hostinger-affiliate-plugin")}
                        </label>
                    </div>
                    <div key="components-base-control"
                         className="hostinger-affiliate-block-input-control hostinger-affiliate-block-input-control--is-product-edit-button">
                        <Button
                            variant="secondary"
                            key="hostinger-affiliate-block-products-change"
                            disabled={!props.attributes.ready}
                            onClick={() => props.setAttributes({ready: false, products_selected_open: true})}
                        >
                            <span className="dashicons dashicons-edit"></span>
                            {__(
                                " Add/Edit products to list",
                                "hostinger-affiliate-plugin"
                            )}
                        </Button>
                    </div>
                </>
            </>);
        }

    }

    if (props.attributes.display_type == "comparison_table") {
        content.push(
            <>
                {selected_display_type_component}
                <TableConfiguration
                    setAttributes={props.setAttributes}
                    attributes={props.attributes}
                />
            </>
        );

        const table_options = [
                {
                    value: 0,
                    label: __("-- Choose table data --", "hostinger-affiliate-plugin"),
                },
                ...hst_affiliate_data.block.tables[props.attributes.marketplace].map((item) => ({
                    value: item.ID,
                    label: item.post_title,
                })),
            ],
            edit_table_button = [];

        if (props.attributes.table_id) {
            edit_table_button.push(
                <>
                    <div key="components-base-control">
                        <Button
                            variant="primary"
                            key="hostinger-affiliate-block-products-add-new-table"
                            className="hostinger-affiliate-block-input-control hostinger-affiliate-block-input-edit-table"
                            onClick={onEditTable}
                            disabled={!props.attributes.ready}
                        >
                            {__(" Edit table", "hostinger-affiliate-plugin")}
                        </Button>
                    </div>
                </>
            );
        }

        if (props.attributes.ready) {
            table_control_content.push(
                <>
                    <SelectControl
                        label={__("Table data", "hostinger-affiliate-plugin")}
                        value={props.attributes.table_id}
                        options={table_options}
                        disabled={!props.attributes.ready}
                        onChange={(value) =>
                            props.setAttributes({table_id: parseInt(value)})
                        }
                    />

                    {edit_table_button}

                    <div key="components-base-control">
                        <Button
                            variant="secondary"
                            key="hostinger-affiliate-block-products-add-new-table"
                            className="hostinger-affiliate-block-input-control hostinger-affiliate-block-input-add-new-table"
                            onClick={onAddNewTable}
                            disabled={!props.attributes.ready}
                        >
                            <svg
                                xmlns="http://www.w3.org/2000/svg"
                                width="21"
                                height="20"
                                viewBox="0 0 21 20"
                                fill="none"
                            >
                                <path
                                    d="M9.87533 10.6253H5.29199C5.11491 10.6253 4.96647 10.5651 4.84668 10.4446C4.72689 10.3241 4.66699 10.1748 4.66699 9.99668C4.66699 9.81855 4.72689 9.67046 4.84668 9.55241C4.96647 9.43435 5.11491 9.37533 5.29199 9.37533H9.87533V4.79199C9.87533 4.61491 9.93557 4.46647 10.0561 4.34668C10.1766 4.22689 10.3259 4.16699 10.504 4.16699C10.6821 4.16699 10.8302 4.22689 10.9482 4.34668C11.0663 4.46647 11.1253 4.61491 11.1253 4.79199V9.37533H15.7087C15.8857 9.37533 16.0342 9.43557 16.154 9.55605C16.2738 9.67655 16.3337 9.82586 16.3337 10.004C16.3337 10.1821 16.2738 10.3302 16.154 10.4482C16.0342 10.5663 15.8857 10.6253 15.7087 10.6253H11.1253V15.2087C11.1253 15.3857 11.0651 15.5342 10.9446 15.654C10.8241 15.7738 10.6748 15.8337 10.4967 15.8337C10.3186 15.8337 10.1705 15.7738 10.0524 15.654C9.93435 15.5342 9.87533 15.3857 9.87533 15.2087V10.6253Z"
                                    fill="#307CBA"
                                />
                            </svg>
                            {__(" Add new table", "hostinger-affiliate-plugin")}
                        </Button>
                    </div>
                </>
            );

            title_control_content.push(title_length_field);
        }

    }

    // List controls

    if (list_control_content.length > 0) {
        list_controls.push(
            <PanelBody
                title={__("Lists", "hostinger-affiliate-plugin")}
                initialOpen={false}
            >
                {list_control_content}
            </PanelBody>
        );
    }

    // Title controls

    if (title_control_content.length > 0) {
        title_controls.push(
            <PanelBody
                title={__("Title", "hostinger-affiliate-plugin")}
                initialOpen={false}
            >
                {title_control_content}
            </PanelBody>
        );
    }

    // Description controls

    if (description_control_content.length > 0) {
        description_controls.push(
            <PanelBody
                title={__("Description", "hostinger-affiliate-plugin")}
                initialOpen={false}
            >
                {description_control_content}
            </PanelBody>
        );
    }

    // Buy now controls

    if (buy_button_controls_content.length > 0) {
        buy_button_controls.push(
            <PanelBody
                title={__("Buy button", "hostinger-affiliate-plugin")}
                initialOpen={false}
            >
                {buy_button_controls_content}
            </PanelBody>
        );
    }

    // Template controls

    if (template_control_content.length > 0) {
        template_controls.push(
            <PanelBody
                title={__("Templates and Styles", "hostinger-affiliate-plugin")}
                initialOpen={false}
            >
                {template_control_content}
            </PanelBody>
        );
    }

    // Table controls

    if (table_control_content.length > 0) {
        table_controls.push(
            <PanelBody
                title={__("Table Configuration", "hostinger-affiliate-plugin")}
                initialOpen={false}
            >
                {table_control_content}
            </PanelBody>
        );
    }

    inspector_controls.push(
        <>
            <InspectorControls key="hostinger-affiliate-block-display-type-control">
                <PanelBody title={__("General Settings", "hostinger-affiliate-plugin")}>
                    <SelectControl
                        label={__("Select A Display Type", "hostinger-affiliate-plugin")}
                        value={props.attributes.display_type}
                        options={[
                            {
                                value: "",
                                label: __(
                                    "-- Select from list --",
                                    "hostinger-affiliate-plugin"
                                ),
                            },
                            {
                                value: "single_product_card",
                                label: __("Single Product Card", "hostinger-affiliate-plugin"),
                            },
                            {
                                value: "multiple_product_list",
                                disabled: false,
                                label: __(
                                    "Multiple Product List",
                                    "hostinger-affiliate-plugin"
                                ),
                            },
                            {
                                value: "comparison_table",
                                disabled: false,
                                label: __("Comparison Table", "hostinger-affiliate-plugin"),
                            },
                        ]}
                        onChange={(value) => changeDisplayType(value)}
                    />
                    {inspector_control_content}
                </PanelBody>
                {list_controls}
                {title_controls}
                {template_controls}
                {description_controls}
                {buy_button_controls}
                {table_controls}
            </InspectorControls>
        </>
    );

    // Everything is ready.
    if (props.attributes.ready) {
        return (
            <div {...useBlockProps()}>
                {inspector_controls}
                <ServerSideRender
                    key="hostinger-affiliate-server-side-renderer"
                    block="hostinger-affiliate-plugin/mercado-block"
                    attributes={props.attributes}
                />
            </div>
        );
    }

    // Display type is not selected
    if (props.attributes.display_type == "") {
        content.push(
            <>
                <HostingerLogo></HostingerLogo>
                <div className="hostinger-block-display-selector">
                    <div className="hostinger-block-display-selector__title"
                    >
                        {__("Link Mercado Livre products", "hostinger-affiliate-plugin")}
                    </div>

                    <div className="hostinger-block-display-selector__subtitle">
                        {__(
                            "Choose how the product block will look like in your post",
                            "hostinger-affiliate-plugin"
                        )}
                    </div>

                    <DisplayTypeSelector
                        entries={display_types}
                        changeDisplayType={changeDisplayType}
                        buttonClass="hostinger-block-button--is-primary"
                    />
                </div>
            </>
        );
    }

    return (
        <div {...useBlockProps()}>
            {inspector_controls}
            {content}
        </div>
    );
}
