
import React from "react";
import styled from "styled-components";
import PropTypes from "prop-types";

const StyledButton = styled.button`
  display: flex;
  padding: 12px 32px;
  justify-content: center;
  align-items: center;
  gap: 12px;
  border-radius: 4px !important;
  background: ${(props) =>
    props.variant === "outline" ? "transparent" : "var(--primary--500)"};
  height: 48px;
  color: ${(props) =>
    props.variant === "outline" ? "var(--primary--500)" : "var(--neutral--0)"};
  border: ${(props) =>
    props.variant === "outline" ? "1px solid var(--neutral--100)" : "none"};
  outline: none;
  cursor: pointer;

  &:hover {
    background-image: linear-gradient(
      0deg,
      rgba(0, 0, 0, 0.05),
      rgba(0, 0, 0, 0.05)
    );
  }

  &:disabled {
    background-color: var(--neutral--300);
    cursor: not-allowed;
  }
`;

function Button({ onClick, children, variant, className, disabled }) {
  return (
    <StyledButton
      className={className}
      variant={variant}
      onClick={onClick}
      disabled={disabled}
    >
      {children}
    </StyledButton>
  );
}

Button.propTypes = {
  variant: PropTypes.oneOf(["outline", "default"]),
};

export default Button;
